import{_ as l,o as t,c as i,S as o}from"./chunks/framework.C6RQlTYc.js";const g=JSON.parse('{"title":"模型幻觉","description":"","frontmatter":{},"headers":[],"relativePath":"直击概念/17ai/s_ai_20-hallucination.md","filePath":"直击概念/17ai/s_ai_20-hallucination.md","lastUpdated":1778207238000}'),n={name:"直击概念/17ai/s_ai_20-hallucination.md"};function r(e,a,s,u,h,c){return t(),i("div",null,[...a[0]||(a[0]=[o('<h1 id="模型幻觉" tabindex="-1">模型幻觉 <a class="header-anchor" href="#模型幻觉" aria-label="Permalink to &quot;模型幻觉&quot;">​</a></h1><h2 id="概念" tabindex="-1">概念 <a class="header-anchor" href="#概念" aria-label="Permalink to &quot;概念&quot;">​</a></h2><p>模型幻觉（Hallucination）指 LLM <strong>生成的内容与事实不符，但以非常自信且合理的口吻呈现</strong>。这是所有 LLM 共通的固有问题，源自其核心机制——预测下一个 token，而非真正&quot;理解&quot;或&quot;知道&quot;事实。</p><p>简单说：LLM 被训练成编造听起来合理的文本，而很多时候它确实碰巧编对了，但出错时同样自信。</p><h2 id="幻觉的类型" tabindex="-1">幻觉的类型 <a class="header-anchor" href="#幻觉的类型" aria-label="Permalink to &quot;幻觉的类型&quot;">​</a></h2><h3 id="事实性幻觉-factuality-hallucination" tabindex="-1">事实性幻觉（Factuality Hallucination） <a class="header-anchor" href="#事实性幻觉-factuality-hallucination" aria-label="Permalink to &quot;事实性幻觉（Factuality Hallucination）&quot;">​</a></h3><p>生成内容与已知事实矛盾：</p><ul><li><strong>捏造数据</strong>：编造不存在的研究数据、统计数据</li><li><strong>捏造引用</strong>：编造不存在的论文、书籍、法律条文</li><li><strong>人物张冠李戴</strong>：把 A 的事迹归给 B</li><li><strong>时间错乱</strong>：混淆历史事件的时间线</li></ul><h3 id="忠实性幻觉-faithfulness-hallucination" tabindex="-1">忠实性幻觉（Faithfulness Hallucination） <a class="header-anchor" href="#忠实性幻觉-faithfulness-hallucination" aria-label="Permalink to &quot;忠实性幻觉（Faithfulness Hallucination）&quot;">​</a></h3><p>生成内容与给定的上下文或指令不一致：</p><ul><li><strong>偏离指令</strong>：忽略用户明确的限制条件</li><li><strong>上下文污染</strong>：遗忘或扭曲上文提到的信息</li><li><strong>过度总结</strong>：总结时添加原文没有的内容</li></ul><h2 id="幻觉的成因" tabindex="-1">幻觉的成因 <a class="header-anchor" href="#幻觉的成因" aria-label="Permalink to &quot;幻觉的成因&quot;">​</a></h2><ol><li><strong>训练数据噪声</strong>：互联网语料本身包含大量错误信息</li><li><strong>概率生成本质</strong>：模型优化的是&quot;像不像人话&quot;，不是&quot;对不对&quot;</li><li><strong>知识截止日期</strong>：训练数据有截止时间，之后的事物全靠&quot;猜&quot;</li><li><strong>长尾知识不足</strong>：冷门领域在训练数据中占比小，容易出错</li><li><strong>对齐训练副作用</strong>：为满足&quot;有帮助&quot;而过度回答，宁错不缺</li><li><strong>上下文窗口遗漏</strong>：长上下文中的关键信息被注意力机制稀释</li></ol><h2 id="缓解策略" tabindex="-1">缓解策略 <a class="header-anchor" href="#缓解策略" aria-label="Permalink to &quot;缓解策略&quot;">​</a></h2><h3 id="技术层面" tabindex="-1">技术层面 <a class="header-anchor" href="#技术层面" aria-label="Permalink to &quot;技术层面&quot;">​</a></h3><ul><li><strong>RAG</strong>：让模型基于检索到的真实文档回答（详见 RAG 章节）</li><li><strong>强约束 Prompt</strong>：明确要求&quot;只基于提供的信息回答，不知道就说不知道&quot;</li><li><strong>降低 Temperature</strong>：生成事实内容时用低温度减少随机性</li><li><strong>Self-Consistency</strong>：多次生成取多数结果</li><li><strong>Grounding / Fact-checking</strong>：用外部工具验证生成内容</li></ul><h3 id="产品层面" tabindex="-1">产品层面 <a class="header-anchor" href="#产品层面" aria-label="Permalink to &quot;产品层面&quot;">​</a></h3><ul><li>标注&quot;AI 生成，仅供参考&quot;</li><li>提供信息来源链接</li><li>对关键场景（医疗、法律等）强制人工审核</li><li>设置置信度阈值，低置信度内容加警告</li></ul><h2 id="前端实践" tabindex="-1">前端实践 <a class="header-anchor" href="#前端实践" aria-label="Permalink to &quot;前端实践&quot;">​</a></h2><ul><li>对 AI 生成的可操作内容（如代码、配置、支付信息）<strong>不要直接执行</strong>，先让用户确认</li><li>展示 AI 回答时附上来源标注</li><li>用 UI 设计区分 AI 推断内容与确定内容（如斜体 vs 正常字体）</li></ul><h2 id="面试常问" tabindex="-1">面试常问 <a class="header-anchor" href="#面试常问" aria-label="Permalink to &quot;面试常问&quot;">​</a></h2><ul><li>什么是模型幻觉？根本原因是什么？</li><li>前端如何设计来降低幻觉带来的风险？</li><li>RAG 为什么能缓解幻觉？</li></ul><h2 id="参考" tabindex="-1">参考 <a class="header-anchor" href="#参考" aria-label="Permalink to &quot;参考&quot;">​</a></h2><ul><li><a href="https://arxiv.org/abs/2202.03629" target="_blank" rel="noreferrer">Survey of Hallucination in Natural Language Generation</a></li><li><a href="https://platform.openai.com/docs/guides/prompt-engineering" target="_blank" rel="noreferrer">OpenAI: Reducing Hallucinations</a></li></ul>',24)])])}const q=l(n,[["render",r]]);export{g as __pageData,q as default};
